1	import {
2	  isRejection,
3	  PluginError,
4	  type AgentContext,
5	  type HookBus,
6	} from '@ax/core';
7	import type { ChunkBuffer } from './chunk-buffer.js';
8	import type { PhaseEvent, SseFrame, StreamChunk } from './types.js';
9	
10	// ---------------------------------------------------------------------------
11	// SSE handler factory.
12	//
13	// Wires GET /api/chat/stream/:reqId. Per request:
14	//
15	//   1. auth:require-user → 401 on rejection.
16	//   2. conversations:get-by-req-id → 404 (NOT 403) on not-found.
17	//      404-not-403 is intentional (J9): we don't tell foreign callers
18	//      whether a reqId exists at all.
19	//   3. agents:resolve(agentId, userId) → 404 same posture as above.
20	//   4. Open the stream, replay the buffer's current chunks for this
21	//      reqId, then attach BOTH a `chat:stream-chunk` subscriber (filtered
22	//      by reqId) AND a `chat:turn-end` subscriber (filtered by
23	//      conversationId). The chunk subscriber emits one `data:` frame
24	//      per chunk; the turn-end subscriber emits a final `done: true`
25	//      and closes.
26	//
27	// Subscribers are unwired on:
28	//   - `done: true` emitted (turn-end)
29	//   - client disconnect (res.stream's onClose)
30	//
31	// Keepalive: a 25 s `:\n\n` heartbeat keeps the connection alive through
32	// proxies that idle-cull. The sweep is a SINGLE setInterval per
33	// connection; cleared in onClose.
34	// ---------------------------------------------------------------------------
35	
36	const SSE_KEEPALIVE_MS = 25_000;
37	
38	// Duck-typed request/response. The full @ax/http-server `HttpResponse` adds
39	// `stream()` (we extended it for this slice); we re-declare just the
40	// piece we need so this file stays free of @ax/http-server imports
41	// (Invariant I2).
42	export interface RouteRequest {
43	  readonly headers: Record<string, string>;
44	  readonly body: Buffer;
45	  readonly cookies: Record<string, string>;
46	  readonly query: Record<string, string>;
47	  readonly params: Record<string, string>;
48	  signedCookie(name: string): string | null;
49	}
50	
51	export interface RouteStream {
52	  write(chunk: string | Buffer): void;
53	  close(): void;
54	  onClose(handler: () => void): void;
55	}
56	
57	export interface RouteResponse {
58	  status(n: number): RouteResponse;
59	  header(name: string, value: string): RouteResponse;
60	  json(v: unknown): void;
61	  text(s: string): void;
62	  end(): void;
63	  stream(opts?: { contentType?: string }): RouteStream;
64	}
65	
66	export interface SseHandlerDeps {
67	  bus: HookBus;
68	  initCtx: AgentContext;
69	  buffer: ChunkBuffer;
70	}
71	
72	/**
73	 * Build the GET /api/chat/stream/:reqId handler. The SSE handler factory
74	 * also returns the bus subscriber the channel-web plugin needs to attach
75	 * to `chat:stream-chunk` so the buffer fills as chunks arrive — this
76	 * keeps subscriber + handler in one file (the handler reads from the
77	 * same buffer).
78	 */
79	export function createSseHandler(deps: SseHandlerDeps) {
80	  const PLUGIN_NAME = '@ax/channel-web';
81	
82	  /** Helper — format a single frame as a complete SSE event line. */
83	  function formatFrame(frame: SseFrame): string {
84	    // Newlines inside JSON.stringify output are escaped; \n separators
85	    // delimit the SSE event. The browser EventSource splits on \n\n.
86	    return `data: ${JSON.stringify(frame)}\n\n`;
87	  }
88	
89	  return async function handle(
90	    req: RouteRequest,
91	    res: RouteResponse,
92	  ): Promise<void> {
93	    // 1) Authenticate.
94	    let userId: string;
95	    try {
96	      const result = await deps.bus.call<
97	        { req: RouteRequest },
98	        { user: { id: string; isAdmin: boolean } }
99	      >('auth:require-user', deps.initCtx, { req });
100	      userId = result.user.id;
101	    } catch (err) {
102	      // Both PluginError('unauthenticated') and bus.fire-style rejections
103	      // collapse to 401 — the route is closed by default.
104	      if (err instanceof PluginError || isRejection(err)) {
105	        res.status(401).json({ error: 'unauthenticated' });
106	        return;
107	      }
108	      throw err;
109	    }
110	
111	    // 2) Resolve the reqId → conversation (J9 — server-derived ACL).
112	    const reqId = req.params.reqId;
113	    if (typeof reqId !== 'string' || reqId.length === 0) {
114	      // Same 404 posture as a missing row — the URL didn't shape into
115	      // a conversation we own.
116	      res.status(404).json({ error: 'not-found' });
117	      return;
118	    }
119	    let conversationId: string;
120	    let agentId: string;
121	    try {
122	      const conv = await deps.bus.call<
123	        { reqId: string; userId: string },
124	        {
125	          conversationId: string;
126	          agentId: string;
127	          userId: string;
128	          activeReqId: string | null;
129	        }
130	      >('conversations:get-by-req-id', deps.initCtx, { reqId, userId });
131	      conversationId = conv.conversationId;
132	      agentId = conv.agentId;
133	    } catch (err) {
134	      // not-found OR forbidden OR anything else from the lookup → 404.
135	      // We deliberately collapse to the same code so callers can't tell
136	      // "your reqId doesn't exist" from "you don't own it" (J9).
137	      if (err instanceof PluginError) {
138	        res.status(404).json({ error: 'not-found' });
139	        return;
140	      }
141	      throw err;
142	    }
143	
144	    // 3) ACL the conversation's agent against the calling user. Same
145	    // 404-not-403 posture: an agent the user can no longer reach
146	    // shouldn't even confirm the conversation is theirs.
147	    try {
148	      await deps.bus.call<
149	        { agentId: string; userId: string },
150	        unknown
151	      >('agents:resolve', deps.initCtx, { agentId, userId });
152	    } catch (err) {
153	      if (err instanceof PluginError) {
154	        res.status(404).json({ error: 'not-found' });
155	        return;
156	      }
157	      throw err;
158	    }
159	
160	    // 4) Open the SSE stream. From here on we own the response — write
161	    // failures and exceptions degrade to a quiet close.
162	    const stream = res.status(200).stream({
163	      contentType: 'text/event-stream; charset=utf-8',
164	    });
165	
166	    let closed = false;
167	    let keepaliveTimer: ReturnType<typeof setInterval> | null = null;
168	
169	    // Subscriber keys are unique per connection so multiple SSE
170	    // listeners on the same reqId (multi-tab) each get their own
171	    // subscription instead of fighting over a shared one. Mixing in
172	    // crypto-random isn't strictly needed (the bus uses the key only
173	    // for unsubscribe), but it keeps two opens on the same reqId
174	    // cleanly distinguishable in logs.
175	    const subscriberSuffix = `${reqId}-${Math.random().toString(36).slice(2, 10)}`;
176	    const chunkSubKey = `${PLUGIN_NAME}/sse-chunk/${subscriberSuffix}`;
177	    const phaseSubKey = `${PLUGIN_NAME}/sse-phase/${subscriberSuffix}`;
178	    const turnEndSubKey = `${PLUGIN_NAME}/sse-turn-end/${subscriberSuffix}`;
179	    const turnErrorSubKey = `${PLUGIN_NAME}/sse-turn-error/${subscriberSuffix}`;
180	
181	    const cleanup = (): void => {
182	      if (closed) return;
183	      closed = true;
184	      if (keepaliveTimer !== null) {
185	        clearInterval(keepaliveTimer);
186	        keepaliveTimer = null;
187	      }
188	      // unsubscribe is idempotent if no match — safe to call even when a
189	      // subscriber was never registered (e.g. error in setup).
190	      deps.bus.unsubscribe('chat:stream-chunk', chunkSubKey);
191	      deps.bus.unsubscribe('chat:phase', phaseSubKey);
192	      deps.bus.unsubscribe('chat:turn-end', turnEndSubKey);
193	      deps.bus.unsubscribe('chat:turn-error', turnErrorSubKey);
194	    };
195	
196	    stream.onClose(() => {
197	      cleanup();
198	    });
199	
200	    const safeWrite = (frame: SseFrame): void => {
201	      if (closed) return;
202	      try {
203	        stream.write(formatFrame(frame));
204	      } catch {
205	        cleanup();
206	        try {
207	          stream.close();
208	        } catch {
209	          // already closed
210	        }
211	      }
212	    };
213	
214	    // 4a) Replay the existing buffer BEFORE attaching the live
215	    // subscriber. If we attached the subscriber first and THEN drained,
216	    // a chunk that fired in between would arrive twice (once via the
217	    // subscriber, once via the buffer drain). If we drained first and
218	    // THEN attached, a chunk fired in between would be lost. We do
219	    // drain-first because the bus runs subscribers serially: the
220	    // subscribe call below executes synchronously after this drain,
221	    // and bus.fire() can't interleave with the same async tick (it
222	    // awaits each subscriber). The narrow window where a chunk lands
223	    // in the buffer DURING the drain is harmless because we re-snapshot
224	    // a copy via `tail()`, so any concurrent appends are visible to
225	    // the subscriber pass that follows.
226	    //
227	    // Phase replays first — it's "before content" by construction (the
228	    // buffer evicts phase as soon as a content chunk lands), so emitting
229	    // it ahead of the chunks matches the order the original turn fired.
230	    const replayPhase = deps.buffer.tailPhase(reqId);
231	    if (replayPhase !== null) {
232	      safeWrite({ reqId, phase: replayPhase });
233	    }
234	    const replay = deps.buffer.tail(reqId);
235	    for (const chunk of replay) {
236	      // The chunk *is* a valid SseFrame variant — types align by design.
237	      safeWrite(chunk);
238	    }
239	
240	    // 4b) Attach the live chunk subscriber. Filter by reqId so multiple
241	    // in-flight conversations sharing the same host don't bleed.
242	    deps.bus.subscribe<StreamChunk>(
243	      'chat:stream-chunk',
244	      chunkSubKey,
245	      async (_ctx, payload) => {
246	        if (payload.reqId !== reqId) return undefined;
247	        safeWrite(payload);
248	        // Subscribers are observation-only here; we never reject or
249	        // mutate. Returning undefined means "pass through".
250	        return undefined;
251	      },
252	    );
