254	    // 4b-bis) Attach the live phase subscriber. Same filter posture as
255	    // chunks; subscribers are observation-only and never veto.
256	    deps.bus.subscribe<PhaseEvent>(
257	      'chat:phase',
258	      phaseSubKey,
259	      async (_ctx, payload) => {
260	        if (payload.reqId !== reqId) return undefined;
261	        safeWrite({ reqId: payload.reqId, phase: payload.phase });
262	        return undefined;
263	      },
264	    );
265	
266	    // 4c) Attach the turn-end subscriber. Filter by ctx.conversationId
267	    // so a turn-end on a different conversation doesn't close us out.
268	    deps.bus.subscribe<{ reqId?: string; reason?: string }>(
269	      'chat:turn-end',
270	      turnEndSubKey,
271	      async (ctx, _payload) => {
272	        if (ctx.conversationId !== conversationId) return undefined;
273	        // Emit the done frame, evict the buffer (this turn is over),
274	        // then close. The eviction here is the success path; the TTL
275	        // sweep in chunk-buffer is the fallback for browsers that
276	        // never get here (closed mid-stream).
277	        safeWrite({ reqId, done: true });
278	        deps.buffer.evictReqId(reqId);
279	        cleanup();
280	        try {
281	          stream.close();
282	        } catch {
283	          // already closed
284	        }
285	        return undefined;
286	      },
287	    );
