289	    // 4c-bis) Attach the turn-error subscriber. The orchestrator fires
290	    // `chat:turn-error` (carrying the ORIGINAL agent:invoke reqId) when a
291	    // turn ends abnormally — the runner died mid-turn or wedged past the
292	    // chat timeout — instead of the normal `chat:turn-end`. Without this
293	    // the stream would never get a terminal frame and the client's
294	    // "Thinking…" spinner hangs forever (the keepalive heartbeat keeps the
295	    // connection open). Match by reqId (the precise per-turn key the
296	    // orchestrator carries), emit an `error` frame, evict, and close.
297	    deps.bus.subscribe<{ reqId?: string; reason?: string }>(
298	      'chat:turn-error',
299	      turnErrorSubKey,
300	      async (_ctx, payload) => {
301	        if (payload.reqId !== reqId) return undefined;
302	        safeWrite({ reqId, error: payload.reason ?? 'unknown' });
303	        deps.buffer.evictReqId(reqId);
304	        cleanup();
305	        try {
306	          stream.close();
307	        } catch {
308	          // already closed
309	        }
310	        return undefined;
311	      },
312	    );
313	
314	    // 4d) Keepalive. The SSE comment ":\n\n" is silently dropped by
315	    // EventSource but keeps proxies (and the http-server's idle
316	    // timeout) from culling the connection. setInterval handle is
317	    // unref'd so a hung connection doesn't block process exit.
318	    keepaliveTimer = setInterval(() => {
319	      if (closed) return;
320	      try {
321	        stream.write(':\n\n');
322	      } catch {
323	        cleanup();
324	      }
325	    }, SSE_KEEPALIVE_MS);
326	    if (typeof (keepaliveTimer as { unref?: () => void }).unref === 'function') {
327	      (keepaliveTimer as { unref: () => void }).unref();
328	    }
329	
330	    // Handler returns now; the stream lives on until cleanup fires.
331	  };
332	}
333	
334	/**
335	 * Subscriber the plugin attaches at boot to fill the chunk buffer. Lives
336	 * here (not in plugin.ts) so the buffer + write-path stay in one file —
337	 * the SSE handler's `tail()` drain depends on it.
338	 */
339	export function createBufferFillSubscriber(buffer: ChunkBuffer) {
340	  return async function (
341	    _ctx: AgentContext,
342	    payload: StreamChunk,
343	  ): Promise<undefined> {
