347	    if (typeof payload?.reqId !== 'string' || typeof payload?.kind !== 'string') {
348	      return undefined;
349	    }
350	    if (payload.kind === 'text' || payload.kind === 'thinking') {
351	      if (typeof (payload as { text?: unknown }).text !== 'string') {
