359	        toolCallId?: unknown;
360	        toolName?: unknown;
361	        input?: unknown;
362	      };
363	      if (
364	        typeof p.toolCallId !== 'string' ||
365	        typeof p.toolName !== 'string' ||
366	        typeof p.input !== 'object' ||
367	        p.input === null ||
368	        Array.isArray(p.input)
369	      ) {
