377	        toolCallId?: unknown;
378	        output?: unknown;
379	        isError?: unknown;
380	      };
381	      if (
382	        typeof p.toolCallId !== 'string' ||
383	        typeof p.output !== 'string' ||
384	        (p.isError !== undefined && typeof p.isError !== 'boolean')
385	      ) {
