387	      }
388	      buffer.append(payload as StreamChunk);
389	      return undefined;
390	    }
391	    return undefined;
392	  };
393	}
394	
395	/**
396	 * Sister to `createBufferFillSubscriber`, but for `chat:phase`. Captures
397	 * the latest phase per reqId so an SSE handler attaching after the phase
398	 * fired still sees it on replay.
399	 */
400	export function createPhaseFillSubscriber(buffer: ChunkBuffer) {
401	  return async function (
402	    _ctx: AgentContext,
403	    payload: PhaseEvent,
404	  ): Promise<undefined> {
405	    if (
406	      typeof payload?.reqId !== 'string' ||
407	      payload.reqId.length === 0 ||
408	      payload?.phase !== 'sandbox-starting'
409	    ) {
410	      return undefined;
411	    }
412	    buffer.appendPhase(payload.reqId, payload.phase);
413	    return undefined;
414	  };
415	}
416	
417	/**
418	 * Turn-end subscriber the plugin attaches at boot. Pre-evicts the buffer
419	 * for reqIds that ended successfully so the per-connection turn-end
420	 * subscriber is the only path that needs to fire the done frame. Lives
421	 * here for the same one-file reason as the chunk filler.
422	 *
423	 * NOTE: this subscriber MUST NOT close any per-connection streams — it
424	 * runs on the host bus and doesn't know about the SSE handlers. Per-
425	 * connection turn-end handling is inside `createSseHandler` and matches
426	 * `ctx.conversationId`. We keep this subscriber separate because a
427	 * conversation may end without any SSE listener attached, and the
428	 * buffer should still be cleaned up.
429	 */
430	export function createTurnEndEvictor(buffer: ChunkBuffer) {
431	  return async function (
432	    _ctx: AgentContext,
433	    payload: { reqId?: string },
434	  ): Promise<undefined> {
435	    if (typeof payload?.reqId === 'string' && payload.reqId.length > 0) {
