      <StubRuntimeProvider>
        <AgentStatus />
      </StubRuntimeProvider>,
    );
    const row = container.querySelector('.agent-status');
    expect(row).toBeTruthy();
    expect(row?.classList.contains('visible')).toBe(false);
  });

